import{_ as e,o as t,c as o,a3 as i}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 牛","description":"丑牛——勤恳踏实，任劳任怨","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 牛","description":"丑牛——勤恳踏实，任劳任怨"},"headers":[],"relativePath":"changshi/shengxiao/niu.md","filePath":"changshi/shengxiao/niu.md","lastUpdated":1779783531000}'),n={name:"changshi/shengxiao/niu.md"};function s(r,a,p,c,h,l){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="丑牛" tabindex="-1">丑牛 <a class="header-anchor" href="#丑牛" aria-label="Permalink to &quot;丑牛&quot;">​</a></h1><blockquote><p>地支「丑」· 丑时（01:00–03:00）· 五行属土 · 阴阳为阴</p></blockquote><p>勤勤恳恳的老牛在丑时反刍最细、最慢、最舒适。在农耕时代，牛是人类非常重要的伙伴——可以拉车、拉犁，以草为食却回馈人们牛奶。在我国文化中，牛一直是任劳任怨、不求回报的象征。</p><h2 id="生肖故事-一步三把草籽" tabindex="-1">生肖故事：一步三把草籽 <a class="header-anchor" href="#生肖故事-一步三把草籽" aria-label="Permalink to &quot;生肖故事：一步三把草籽&quot;">​</a></h2><p>相传在古代，牛是玉帝殿前的差役。有一次农夫托牛给玉帝捎口信，请求带些草籽打扮荒凉的人间。牛自告奋勇要去撒草种。玉帝嘱咐它「走三步撒一把草籽」。</p><p>没想到牛刚跨出南天门就跌了一跤，脑袋摔得晕晕乎乎，犯下了「一步撒三把草籽」的错误。第二年大地上野草丛生，农夫无法播种庄稼。玉帝知道牛坏了事，罚它和它的子子孙孙只准吃草、帮助农夫除草干活。</p><p>玉帝怒气未消，朝牛踢了一脚——牛从天上摔到人间，嘴巴朝下，摔掉了一排上牙。直到今天，牛的那排上牙还没有长出来。</p><p>但牛是个知过即改的好动物，它拉车犁田踏实勤恳，任劳任怨，博得了人们的一致好评。在排生肖时，人们都积极推举它为生肖。</p>',8)])])}const u=e(n,[["render",s]]);export{_ as __pageData,u as default};
